#nullable enable // autogenerated

using MVZ2.GameContent.Models;
using MVZ2.Vanilla.Grids;
using MVZ2.Vanilla.Models;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Grids;
using MVZ2Logic.Models;
using PVZEngine;
using PVZEngine.Buffs;
using PVZEngine.Definitions;
using PVZEngine.Grids;
using PVZEngine.Modifiers;
using Tools;

namespace MVZ2.GameContent.Buffs.Grids
{
    [AutoBuffDefinition(VanillaBuffNames.Grid.brokenTile)]
    public class BrokenTileBuff : BuffDefinition
    {
        public BrokenTileBuff(string nsp, string name) : base(nsp, name)
        {
            AddModifier(new BooleanModifier(LogicGridProps.DISABLED, true));
            AddModelInsertion(LogicModelHelper.ANCHOR_CENTER, MODEL_KEY, VanillaModelID.brokenTile);
        }
        public override void OnCreate(Buff buff)
        {
            base.OnCreate(buff);
            buff.SetProperty(PROP_TIMEOUT_TIMER, TimerHelper.NewSecondTimer(MAX_TIMEOUT_SECONDS));
        }
        public override void PostAdd(Buff buff)
        {
            base.PostAdd(buff);
            UpdateModel(buff);
        }
        public override void PostUpdate(Buff buff)
        {
            base.PostUpdate(buff); ;
            var timeoutTimer = buff.GetProperty<FrameTimer>(PROP_TIMEOUT_TIMER);
            if (timeoutTimer.RunToExpiredOrNull())
            {
                buff.Remove();
            }
            UpdateModel(buff);
        }
        public void UpdateModel(Buff buff)
        {
            var grid = buff.Target as LawnGrid;
            if (grid == null)
                return;
            var model = buff.GetInsertedModel(MODEL_KEY);
            if (model != null)
            {
                var timeoutTimer = buff.GetProperty<FrameTimer>(PROP_TIMEOUT_TIMER);
                bool decayed = (timeoutTimer?.GetPassedPercentage() ?? 0) >= 0.5f;

                model.SetModelProperty("GridType", grid.GetGridModelType());
                model.SetModelProperty("Decayed", decayed);
                model.SortingOrder = 100;
            }
        }
        public const float MAX_TIMEOUT_SECONDS = 180;
        public static readonly NamespaceID MODEL_KEY = VanillaModelKeys.brokenTile;
        public static readonly VanillaBuffPropertyMeta<FrameTimer> PROP_TIMEOUT_TIMER = new VanillaBuffPropertyMeta<FrameTimer>("timeout_timer");
    }
}
